  ('real-estate-appraiser-moex-00028', 'real-estate-appraiser', 'real-estate-appraiser-moex-113-707b521e', 'sub-real-estate-appraiser-05', NULL, 'essay', '都市計畫法第 49條規定，公共設施保留地之徵收或區段徵收，其地價補
償以徵收當期毗鄰非公共設施保留地之平均公告土地現值為準，必要時
得加成補償之。其中，「毗鄰」的界定影響公共設施保留地地主的權益甚
鉅。請分別由「地理接觸說」及「受益範圍說」等觀點加以論述「毗鄰」
之內涵。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:29+00:00", "source_pdf_sha1": "d54dbbea15fd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "905", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "土地利用法規", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
