  ('real-estate-appraiser-moex-00031', 'real-estate-appraiser', 'real-estate-appraiser-moex-113-9cd45b90', 'sub-real-estate-appraiser-06', NULL, 'essay', '甲、乙、丙、丁、戊五人共有一宗 A地，應有部分登記分別為：甲十分
之三、乙十分之三、丙十分之二、丁十分之一、戊十分之一。乙未經甲、
丙、丁、戊四人同意將應有部分設定普通抵押權於 X銀行。甲提出共有
A地分割，並主張分割後將前揭普通抵押權移存於乙所分得之土地。試
問甲的提議，依法規定在那些情形下，可以成立？請評述之。又假設 A
地分割時，戊以金錢補償，依法規定應受補償人戊，對甲、乙、丙、丁
四人所分得之土地，可取得何種權利？對 X銀行有何影響？試分別申述
之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:29+00:00", "source_pdf_sha1": "f60b3d5833c8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "905", "s": "0301", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權與不動產法規", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL)
